def gen(rng, size):
    n = max(3, size)
    grid = [[0] * n for _ in range(n)]
    for r in range(n):
        for c in range(n):
            if r == c or r + c == n - 1:
                grid[r][c] = rng.randrange(1, 100000)
    if rng.random() < 0.5:
        r = rng.randrange(n)
        c = rng.randrange(n)
        on = (r == c or r + c == n - 1)
        grid[r][c] = 0 if on else rng.randrange(1, 100000)
    return [grid]

