class Solution:
    def checkXMatrix(self, grid):
        n = len(grid)
        for r in range(n):
            for c in range(n):
                on = (r == c) or (r + c == n - 1)
                v = grid[r][c]
                if on and v == 0:
                    return False
                if not on and v != 0:
                    return False
        return True

