class Solution:
    def checkXMatrix(self, grid):
        n = len(grid)
        for r in range(n):
            for c in range(n):
                if r == c or r + c == n - 1:
                    if grid[r][c] == 0:
                        return False
                elif grid[r][c] != 0:
                    return False
        return True

