var checkXMatrix = function(grid) {
    const n = grid.length;
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < n; c++) {
            const on = (r === c) || (r + c === n - 1);
            if (on) {
                if (grid[r][c] === 0) return false;
            } else if (grid[r][c] !== 0) {
                return false;
            }
        }
    }
    return true;
};
